import json, os, sys, time, traceback, urllib.parse
import requests

def load_connector_config():
    try:
        with open('/run/connector.json','r',encoding='utf-8') as f:
            return json.load(f)
    except Exception as e:
        raise RuntimeError(f"Failed to load /run/connector.json: {e}")

def make_session(email, api_token):
    try:
        s = requests.Session()
        s.auth = (email, api_token)
        s.headers.update({'Accept':'application/json'})
        return s
    except Exception as e:
        raise RuntimeError(f"Failed to create HTTP session: {e}")

def clamp(n, lo, hi):
    return max(lo, min(hi, n))

def retry_request(session, method, url, **kwargs):
    # Simple retry with backoff for 429/5xx
    max_attempts = 6
    backoff = 1.0
    last_exc = None
    for attempt in range(1, max_attempts+1):
        try:
            resp = session.request(method, url, timeout=30, **kwargs)
            if resp.status_code == 429:
                ra = resp.headers.get('Retry-After')
                delay = float(ra) if ra and ra.isdigit() else backoff
                time.sleep(delay)
                backoff = min(backoff * 2, 30)
                continue
            if 500 <= resp.status_code < 600:
                time.sleep(backoff)
                backoff = min(backoff * 2, 30)
                continue
            return resp
        except requests.RequestException as re:
            last_exc = re
            time.sleep(backoff)
            backoff = min(backoff * 2, 30)
            continue
    if last_exc:
        raise RuntimeError(f"HTTP request failed after retries: {last_exc}")
    raise RuntimeError("HTTP request failed after retries with unknown error")

def resolve_account_id(site_url, session, email):
    # Uses Jira Cloud user search v3: GET /rest/api/3/user/search?query=<email>
    # Note: Depending on site privacy settings, matching by email may require proper permissions.
    try:
        params = {'query': email, 'maxResults': 50}
        url = f"{site_url}/rest/api/3/user/search"
        resp = retry_request(session, 'GET', url, params=params)
        if resp.status_code != 200:
            raise RuntimeError(f"user/search returned {resp.status_code}: {resp.text}")
        users = resp.json()
        # Prefer exact email match when visible
        lowered = email.strip().lower()
        exact = None
        for u in users:
            try:
                if u.get('emailAddress') and u.get('emailAddress','').lower() == lowered:
                    exact = u
                    break
            except Exception:
                pass
        if not exact and users:
            exact = users[0]
        if not exact:
            raise RuntimeError(f"No user found matching email: {email}")
        aid = exact.get('accountId')
        if not aid:
            raise RuntimeError("Resolved user has no accountId (possibly due to privacy settings)")
        return aid, exact
    except Exception as e:
        raise RuntimeError(f"resolve_account_id failed: {e}")

def build_jql(cfg, account_id_if_known=None):
    try:
        if cfg.get('jql'):
            return cfg['jql']
        id_type = (cfg.get('assigneeIdentifierType') or '').strip().lower()
        assignee_raw = cfg.get('assignee')
        if id_type == 'accountid':
            aid = assignee_raw
        else:
            aid = account_id_if_known
        if not aid:
            raise RuntimeError("Missing assignee accountId for JQL build")
        # Use accountId() function for robust JQL in Cloud
        parts = [f'assignee in (accountId("{aid}"))']
        if cfg.get('projects'):
            proj_vals = [str(p) for p in (cfg.get('projects') or []) if str(p).strip()]
            proj = ', '.join([f'"{p}"' for p in proj_vals])
            if proj:
                parts.append(f'project in ({proj})')
        if cfg.get('statuses'):
            sts_vals = [str(s) for s in (cfg.get('statuses') or []) if str(s).strip()]
            sts = ', '.join([f'"{s}"' for s in sts_vals])
            if sts:
                parts.append(f'status in ({sts})')
        if not cfg.get('includeSubtasks', True):
            parts.append('issuetype != "Sub-task"')
        if cfg.get('sinceUpdated'):
            val = str(cfg['sinceUpdated']).replace('"','\\"')
            parts.append(f'updated >= "{val}"')
        jql = ' AND '.join(parts)
        order_by = cfg.get('orderBy')
        if order_by:
            jql += f' ORDER BY {order_by}'
        return jql
    except Exception as e:
        raise RuntimeError(f"build_jql failed: {e}")

def fetch_all_issues(site_url, session, jql, fields, expand, max_per_page):
    try:
        issues = []
        start_at = 0
        total = None
        # Use the correct Jira search endpoint
        base_url = f"{site_url}/rest/api/3/search"
        page_size = clamp(int(max_per_page or 100), 1, 100)
        while True:
            payload = {
                'jql': jql,
                'startAt': start_at,
                'maxResults': page_size
            }
            # Jira /search POST accepts fields as an array
            if isinstance(fields, list) and len(fields) > 0:
                payload['fields'] = [str(f) for f in fields]
            # Provide expand as a query parameter (comma-separated) for compatibility
            params = None
            if isinstance(expand, list) and len(expand) > 0:
                params = {'expand': ','.join([str(e) for e in expand])}
            resp = retry_request(session, 'POST', base_url, json=payload, params=params)
            if resp.status_code != 200:
                raise RuntimeError(f"search returned {resp.status_code}: {resp.text}")
            data = resp.json()
            batch = data.get('issues', [])
            issues.extend(batch)
            total = data.get('total', len(issues))
            fetched = data.get('startAt', start_at)
            returned = data.get('maxResults', len(batch))
            start_at = fetched + returned
            if len(issues) >= total or len(batch) == 0:
                break
        return {'total': total if total is not None else len(issues), 'issues': issues}
    except Exception as e:
        raise RuntimeError(f"fetch_all_issues failed: {e}")

def main():
    try:
        connector = load_connector_config()
        auth = connector.get('auth') or {}
        cfg = connector.get('configuration') or {}
        site_url = (cfg.get('siteUrl') or '').rstrip('/')
        if not site_url.startswith('http'):
            raise ValueError('configuration.siteUrl must be a full https URL to your Jira Cloud site (e.g., https://your-domain.atlassian.net)')
        email = auth.get('jiraEmail') or os.environ.get('AUTH_JIRAEMAIL')
        token = auth.get('jiraApiToken') or os.environ.get('AUTH_JIRAAPITOKEN')
        if not email or not token:
            raise ValueError('auth.jiraEmail and auth.jiraApiToken are required')
        session = make_session(email, token)
        account_resolved = None
        resolved_user_obj = None
        if not cfg.get('jql'):
            id_type = (cfg.get('assigneeIdentifierType') or '').strip().lower()
            if id_type == 'email':
                account_resolved, resolved_user_obj = resolve_account_id(site_url, session, cfg.get('assignee'))
            elif id_type == 'accountid':
                account_resolved = cfg.get('assignee')
            else:
                raise ValueError("configuration.assigneeIdentifierType must be 'accountId' or 'email'")
        jql = build_jql(cfg, account_resolved)
        result = fetch_all_issues(site_url, session, jql, cfg.get('fields'), cfg.get('expand'), cfg.get('maxResultsPerPage'))
        output = {
            'ok': True,
            'siteUrl': site_url,
            'assigneeIdentifierType': cfg.get('assigneeIdentifierType'),
            'assigneeInput': cfg.get('assignee'),
            'assigneeAccountId': account_resolved,
            'jql': jql,
            'total': result.get('total'),
            'count': len(result.get('issues', [])),
            'issues': result.get('issues', []),
            'note': 'Data fetched via Jira Cloud REST API v3 (/rest/api/3/search).'
        }
        if resolved_user_obj is not None:
            safe_user = dict(resolved_user_obj)
            if 'emailAddress' in safe_user:
                # Keep as-is; visibility depends on site settings. Avoid exposing if None.
                pass
            output['resolvedUser'] = safe_user
        print(json.dumps(output, ensure_ascii=False))
    except Exception as e:
        err = {
            'ok': False,
            'error': {
                'message': str(e),
                'stack': traceback.format_exc(),
                'failedFunction': 'main'
            }
        }
        try:
            print(json.dumps(err, ensure_ascii=False))
        except Exception:
            # Fallback minimal
            sys.stdout.write('{"ok": false, "error": {"message": "Unserializable error"}}')

if __name__ == '__main__':
    main()
